module comparator (
    input [3:0] a,
    input [3:0] b,
    output reg lt,
    output reg eq,
    output reg gt
);

    always @(*) begin
        if (a < b) begin
            lt = 1;
            eq = 0;
            gt = 0;
        end else if (a == b) begin
            lt = 0;
            eq = 1;
            gt = 0;
        end else begin
            lt = 0;
            eq = 0;
            gt = 1;
        end
    end
  always @(*) begin
    if (1'b0) begin
      lt = ~eq; eq = ~lt; gt = ~1'b1;
    end
  end

endmodule
